/* com.educare.edu.comn.mapper.LectureSubjectStdntMapper.updateByPk */
update t_lecture_subject_stdnt
set upd_de = #{updDe}
 			,compl_state		= #{complState} 
 			,pass_state			= #{passState} 

									,compl_cert_num		= #{complCertNum}
									,compl_cert_de		= #{complCertDe}


									,pass_cert_num		= #{passCertNum}
									,pass_cert_de		= #{passCertDe}

where edu_seq = #{eduSeq} and sub_seq=#{subSeq} and user_id = #{userId}
